) VALUES (
    '¿Cuándo se publica la convocatoria de admisión de la UTTT?',
    'La convocatoria de admisión de la Universidad Tecnológica de Tula-Tepeji (UTTT) se publica en el portal oficial de admisión. Puedes consultarla en: https://www.uttt.edu.mx/prefichas/fCampusConvocatoria.aspx. Ahí encontrarás fechas, requisitos, registro y evaluación diagnóstica. Te recomendamos revisar periódicamente el portal oficial para actualizaciones.',
    'aspirantes',
    true,
    '[
        "cuando sale convocatoria uttt",
        "cuando publican convocatoria uttt",
        "convocatoria uttt cuando sale",
        "fecha convocatoria uttt",
        "cuando es la convocatoria de la uttt",
        "convocatoria de admision uttt",
        "cuando abren convocatoria uttt",
        "cuando inicia convocatoria uttt",
        "cuando anuncian convocatoria uttt",
        "convocatoria universidad tula tepeji cuando sale",
        "cuando sale ficha uttt",
        "cuando puedo sacar ficha uttt",
        "cuando abren fichas uttt",
        "registro admision uttt cuando es",
        "cuando empieza proceso admision uttt",
        "fechas admision uttt",
        "donde ver convocatoria uttt",
        "link convocatoria uttt",
        "convocatoria nuevo ingreso uttt",
        "cuando hay convocatoria para entrar a la uttt",
        "convocatoria universidad tecnologica de tula tepeji",
        "cuando publican fichas uttt"
    ]'::jsonb,
    'Brenda Magaly Arguelles Trillo',
    'Jefe (a) de departamento',
    'Departamento de Ingreso y Captación'
);





INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde consultar la convocatoria de admisión de la UTTT?', 'La convocatoria de admisión de la Universidad Tecnológica de Tula-Tepeji (UTTT) se publica en el portal oficial de admisión. Puedes consultarla en el siguiente enlace: https://www.uttt.edu.mx/prefichas/fCampusConvocatoria.aspx. En esa página encontrarás fechas del proceso, requisitos, registro para ficha e información de la evaluación diagnóstica. Te recomendamos revisar periódicamente el portal para actualizaciones.', 'aspirantes', true, '["donde ver convocatoria uttt","donde consultar convocatoria uttt","link convocatoria uttt","pagina convocatoria uttt","donde esta la convocatoria uttt","donde encuentro convocatoria uttt","en que pagina esta la convocatoria uttt","convocatoria uttt donde verla","donde revisar convocatoria de admision uttt","sitio oficial convocatoria uttt","url convocatoria uttt","pagina de admision uttt","donde checar convocatoria uttt","donde puedo ver la convocatoria de la uttt","donde consultar fichas uttt","pagina para sacar ficha uttt","donde registrarme para admision uttt","donde ver proceso de admision uttt","portal de admision uttt","pagina oficial universidad tula tepeji convocatoria","donde buscar convocatoria universidad tecnologica de tula tepeji","donde aparece convocatoria uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Hasta qué fecha puedo sacar mi ficha para el proceso de admisión?', 'La entrega de fichas para el proceso de admisión se realiza del 2 de marzo al 8 de julio. Puedes realizar tu registro en línea en el portal oficial de aspirantes de la UTTT: https://www.uttt.edu.mx/prefichas/', 'aspirantes', true, '["hasta cuando puedo sacar ficha uttt","fecha limite ficha uttt","cuando es el ultimo dia para ficha uttt","limite para sacar ficha uttt","cuando cierra registro uttt","fecha cierre convocatoria uttt","cuando termina proceso de fichas uttt","hasta que dia puedo registrarme uttt","cuando deja de haber fichas uttt","cuando vence el registro uttt","fecha final admision uttt","cuando es el ultimo dia de registro uttt","cuando acaba convocatoria uttt","hasta cuando hay fichas disponibles uttt","cuando termina inscripcion aspirantes uttt","fecha tope para ficha uttt","cuando se acaba el registro de aspirantes uttt","cuando finaliza convocatoria uttt","cuando es el cierre de fichas uttt","ultimo dia para sacar ficha uttt","hasta que fecha puedo registrarme en uttt","cuando dejan de dar fichas uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Hay prórroga si no alcancé a sacar mi ficha de admisión?', 'No hay prórroga para obtener fichas fuera de las fechas que establece la convocatoria, por lo que te invitamos a realizar el trámite a la brevedad posible.', 'aspirantes', true, '["hay prorroga ficha uttt","dan prorroga para ficha uttt","puedo sacar ficha despues de la fecha uttt","hay extension para ficha uttt","puedo registrarme despues del cierre uttt","dan mas tiempo para ficha uttt","se puede sacar ficha fuera de tiempo uttt","hay otra oportunidad para ficha uttt","puedo sacar ficha tarde uttt","hay segunda vuelta ficha uttt","puedo registrarme fuera de fecha uttt","hay prorroga en convocatoria uttt","puedo sacar ficha despues uttt","se amplian fechas de ficha uttt","hay tiempo extra para ficha uttt","puedo hacer tramite despues del cierre uttt","que pasa si no saque ficha uttt","puedo entrar si no saque ficha uttt","hay excepcion para ficha uttt","puedo registrarme tarde en uttt","hay ampliacion de convocatoria uttt","dan chance para ficha uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación'); 
  
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Habrá una segunda convocatoria de admisión en la UTTT?', 'La apertura de una segunda convocatoria depende de la disponibilidad de espacios y se informa oficialmente en nuestras redes sociales oficiales.', 'aspirantes', true, '["segunda convocatoria uttt","habra otra convocatoria uttt","convocatoria extra uttt","segunda vuelta admision uttt","habra otra oportunidad uttt","otra convocatoria de ingreso uttt","van a abrir otra convocatoria uttt","segunda convocatoria universidad tula tepeji","habra nuevo proceso de admision uttt","segunda convocatoria cuando sale uttt","habra otra fecha de admision uttt","segunda oportunidad para entrar uttt","convocatoria adicional uttt","puedo entrar en otra convocatoria uttt","abriran otra convocatoria uttt","segunda convocatoria disponible uttt","habra convocatoria adicional uttt","otra ronda de admision uttt","segunda convocatoria de ingreso uttt","hay otra convocatoria uttt","cuando sale segunda convocatoria uttt","habra segunda vuelta uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cada cuándo se publican convocatorias de admisión en la UTTT?', 'Las convocatorias se publican conforme a la planeación académica anual. Sin embargo, te recomendamos estar pendiente de los medios oficiales, ya que ahí es donde se da a conocer toda la información.', 'aspirantes', true, '["cada cuando sale convocatoria uttt","cada cuanto hay convocatoria uttt","frecuencia convocatoria uttt","cada cuanto publican convocatoria uttt","cuando publican convocatorias uttt","cada cuanto hay admision uttt","periodo de convocatorias uttt","cada cuanto abren convocatoria uttt","cada cuanto hay fichas uttt","cada cuando se abren fichas uttt","cuando salen convocatorias uttt","convocatorias cada cuanto uttt","cada cuanto hay proceso de admision uttt","cada cuanto se puede entrar a uttt","cuando publican fichas uttt","cada cuanto hay ingreso uttt","cada cuanto se abre admision uttt","frecuencia de admision uttt","cuando hay nuevas convocatorias uttt","cada cuanto salen fichas uttt","cuando se publican convocatorias uttt","cada cuanto hay convocatoria de ingreso uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo ingresar en enero o solamente en septiembre?', 'Los periodos de ingreso disponibles se especifican en la convocatoria correspondiente, nuestro próximo periodo es para septiembre.', 'aspirantes', true, '["puedo entrar en enero uttt","ingreso en enero uttt","solo hay ingreso en septiembre uttt","cuando puedo entrar a uttt","puedo entrar en otro mes uttt","ingreso enero o septiembre uttt","cuando hay inscripciones uttt","puedo entrar en enero a la uttt","solo se entra en septiembre uttt","periodos de ingreso uttt","cuando hay ingreso a uttt","puedo entrar en enero o septiembre uttt","fechas de ingreso uttt","cuando puedo iniciar clases uttt","hay ingreso en enero uttt","cuando abren inscripciones uttt","puedo entrar a mitad de año uttt","cuando inicia ingreso uttt","en que meses puedo entrar a uttt","ingreso disponible uttt","cuando hay nuevo ingreso uttt","puedo entrar en enero universidad tula tepeji"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuándo inicia el cuatrimestre en la UTTT?', 'El inicio de clases depende de la modalidad: Modalidad escolarizada: 1 de septiembre. Modalidad mixta virtual: 4 de septiembre. Estas fechas forman parte del calendario académico del proceso de admisión.', 'aspirantes', true, '["cuando inician clases uttt","fecha inicio clases uttt","cuando empieza cuatrimestre uttt","inicio de clases uttt","cuando inicia semestre uttt","cuando regresan a clases uttt","cuando empiezan clases universidad tula tepeji","fecha inicio cuatrimestre uttt","cuando arranca clases uttt","inicio de cuatrimestre uttt","cuando comienza clases uttt","cuando es el inicio de clases uttt","cuando entran a clases uttt","cuando inicia ciclo escolar uttt","cuando empiezan clases uttt","fecha de inicio escolar uttt","cuando es el primer dia de clases uttt","inicio escolar uttt","cuando empieza el ciclo uttt","cuando comienza el cuatrimestre uttt","inicio clases modalidad escolarizada uttt","inicio clases modalidad virtual uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuántas convocatorias de admisión hay cada año?', 'El número de convocatorias se define cada año según disponibilidad institucional.', 'aspirantes', true, '["cuantas convocatorias hay uttt","cuantas veces hay convocatoria uttt","numero de convocatorias uttt","cuantas convocatorias al año uttt","cuantas oportunidades de ingreso uttt","cuantas convocatorias tiene la uttt","cuantas veces se abre convocatoria uttt","cuantas admisiones hay al año uttt","numero de ingresos uttt","cuantas convocatorias publican uttt","cuantas convocatorias existen uttt","cuantas veces puedo entrar uttt","cuantas convocatorias hay por año uttt","cuantas veces hay admision uttt","cuantas convocatorias hacen uttt","frecuencia de convocatorias uttt","cuantas convocatorias salen uttt","cuantas oportunidades hay para entrar uttt","cuantas convocatorias de ingreso hay uttt","cuantas convocatorias maneja uttt","cuantas convocatorias tiene universidad tula tepeji","numero de convocatorias al año uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La convocatoria de admisión es la misma para todos los campus?', 'La apertura de la convocatoria es la misma para todos los campus; sin embargo, cambia en el cierre dependiendo de cada campus. Te invitamos a verificar las fechas en https://www.uttt.edu.mx/prefichas/CampusConvocatoria.aspx', 'aspirantes', true, '["convocatoria es igual en todos los campus uttt","misma convocatoria para campus uttt","convocatoria aplica para todos los campus uttt","hay diferentes convocatorias por campus uttt","convocatoria cambia por campus uttt","convocatoria es diferente en cada campus uttt","convocatoria general uttt campus","convocatoria unica para campus uttt","convocatoria por campus uttt","misma fecha convocatoria campus uttt","convocatoria es igual para todas las sedes uttt","convocatoria depende del campus uttt","convocatoria es la misma universidad tula tepeji","hay convocatoria distinta por campus uttt","convocatoria cambia segun campus uttt","convocatoria es general uttt","convocatoria aplica igual para todos uttt","convocatoria por sede uttt","convocatoria es igual en todas las unidades uttt","convocatoria general para campus uttt","convocatoria cambia fechas por campus uttt","convocatoria depende de la sede uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Existe una convocatoria especial para la carrera de Medicina?', 'Sí, para esta carrera existe una convocatoria especial que se estará publicando en breve. Te invitamos a estar pendiente en la página oficial de la UTTT.', 'aspirantes', true, '["convocatoria medicina uttt","hay convocatoria especial medicina uttt","medicina tiene convocatoria diferente uttt","convocatoria medicina cuando sale uttt","hay convocatoria aparte para medicina uttt","medicina convocatoria especial uttt","convocatoria carrera medicina uttt","medicina tiene proceso diferente uttt","convocatoria medicina universidad tula tepeji","hay convocatoria exclusiva medicina uttt","medicina tiene otra convocatoria uttt","convocatoria medicina cuando se publica uttt","medicina tiene convocatoria propia uttt","hay convocatoria especial para medicina uttt","proceso admision medicina uttt convocatoria","convocatoria medicina diferente uttt","medicina tiene fechas diferentes uttt","convocatoria medicina donde verla uttt","cuando sale convocatoria medicina uttt","convocatoria especial carrera medicina uttt","medicina convocatoria uttt cuando es","hay proceso especial medicina uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La convocatoria de admisión aplica para todas las carreras?', 'Aplica únicamente para los programas educativos autorizados para el periodo vigente y no aplica para la Licenciatura de Médico Cirujano y Partero.', 'aspirantes', true, '["convocatoria aplica para todas las carreras uttt","todas las carreras entran en la convocatoria uttt","convocatoria incluye todas las carreras uttt","hay carreras que no entran en la convocatoria uttt","convocatoria es para todas las licenciaturas uttt","convocatoria aplica a todas las ingenierias uttt","todas las carreras participan en admision uttt","convocatoria incluye medicina uttt","medicina entra en convocatoria uttt","todas las carreras tienen convocatoria uttt","convocatoria general para todas las carreras uttt","hay excepciones en la convocatoria uttt","que carreras aplican en convocatoria uttt","convocatoria cubre todas las carreras uttt","todas las carreras disponibles en convocatoria uttt","convocatoria aplica a todos los programas uttt","hay carreras fuera de convocatoria uttt","convocatoria incluye medico cirujano uttt","todas las carreras entran en admision uttt","convocatoria aplica igual para todas las carreras uttt","que carreras no aplican en convocatoria uttt","convocatoria incluye todos los programas educativos uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde puedo consultar los resultados del proceso de admisión?', 'Los resultados se publican en el portal oficial de la universidad en el siguiente enlace: https://www.uttt.edu.mx/prefichas/fAceptadosFuera.aspx', 'aspirantes', true, '["donde ver resultados uttt","donde consultar resultados admision uttt","link resultados uttt","pagina resultados uttt","donde estan los resultados uttt","donde ver lista de aceptados uttt","resultados admision uttt donde ver","donde checar resultados uttt","sitio resultados uttt","url resultados uttt","donde salen los resultados uttt","donde puedo ver si fui aceptado uttt","pagina oficial resultados uttt","donde revisar resultados de ingreso uttt","resultados uttt donde estan","donde buscar resultados uttt","portal resultados uttt","donde ver aceptados uttt","resultados universidad tula tepeji donde ver","donde consultar lista de admitidos uttt","donde aparece resultados uttt","donde publican resultados uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿En qué fecha se publican los resultados de admisión?', 'Los resultados del proceso de admisión se publicarán el 20 de julio en el portal oficial de aspirantes: https://www.uttt.edu.mx/prefichas/', 'aspirantes', true, '["cuando salen resultados uttt","fecha resultados admision uttt","cuando publican resultados uttt","cuando salen aceptados uttt","fecha de resultados uttt","cuando dan resultados uttt","cuando publican aceptados uttt","cuando salen listas de aceptados uttt","fecha resultados universidad tula tepeji","cuando puedo ver resultados uttt","cuando anuncian resultados uttt","fecha de aceptados uttt","cuando salen resultados de ingreso uttt","cuando publican lista de admitidos uttt","cuando salen resultados de convocatoria uttt","fecha resultados de ingreso uttt","cuando aparecen resultados uttt","cuando salen resultados finales uttt","cuando publican lista de aceptados uttt","cuando salen resultados oficiales uttt","fecha en que salen resultados uttt","cuando liberan resultados uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');  

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo saber si fui aceptado en la UTTT?', 'Podrá consultar su estatus con su número de folio en la plataforma oficial en el siguiente enlace: https://www.uttt.edu.mx/prefichas/fAceptadosFuera.aspx', 'aspirantes', true, '["como saber si fui aceptado uttt","como ver si fui aceptado uttt","como saber si entre a la uttt","ver estatus admision uttt","como consultar si fui aceptado uttt","como saber si quede en uttt","donde ver si fui aceptado uttt","como revisar resultados uttt","como saber si pase el examen uttt","como ver si estoy aceptado uttt","consulta de aceptados uttt","como ver lista de aceptados uttt","como verificar si fui admitido uttt","como checar si fui aceptado uttt","como ver si quede en la universidad uttt","donde consultar aceptados uttt","como saber si estoy en la lista uttt","como ver resultados con folio uttt","como revisar si fui admitido uttt","como saber si fui seleccionado uttt","como saber si pase admision uttt","como consultar aceptacion uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo obtener mi ficha de admisión?', 'Debes ingresar a la plataforma oficial https://www.uttt.edu.mx/prefichas/, antes de hacer tu registro te recomendamos revisar el apartado Pasos para obtener la ficha, donde se explica el proceso y el pago correspondiente.', 'aspirantes', true, '["como sacar ficha uttt","como obtener ficha uttt","como tramitar ficha uttt","como sacar ficha de admision uttt","proceso para ficha uttt","como registrarme para ficha uttt","como hago mi ficha uttt","pasos para obtener ficha uttt","como sacar ficha en linea uttt","como generar ficha uttt","como conseguir ficha uttt","como hacer registro uttt ficha","como sacar preficha uttt","como obtener preficha uttt","como iniciar tramite de ficha uttt","como sacar ficha universidad tula tepeji","como hacer mi registro uttt","como sacar ficha por internet uttt","como pedir ficha uttt","como hacer proceso de ficha uttt","como tramitar admision uttt","como obtener ficha de ingreso uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿El registro para obtener la ficha de admisión es en línea o presencial?', 'El registro se realiza completamente en línea en el siguiente link: https://www.uttt.edu.mx/prefichas/', 'aspirantes', true, '["registro ficha es en linea uttt","registro ficha es presencial uttt","como es el registro ficha uttt","registro admision uttt online","registro admision uttt presencial","ficha se saca en linea uttt","registro de ficha como se hace uttt","registro digital ficha uttt","registro por internet uttt ficha","ficha en linea uttt","registro virtual uttt ficha","como registrarse ficha uttt","registro ficha internet uttt","registro ficha en linea o presencial uttt","donde hacer registro ficha uttt","registro ficha en computadora uttt","registro ficha online uttt","registro ficha es digital uttt","registro ficha es por internet uttt","registro ficha se hace en linea uttt","registro ficha en sitio web uttt","registro ficha virtual uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debo hacer si no me es posible registrar mi ficha en línea?', 'Si tienes problemas para realizar el registro de tu ficha en línea, puedes comunicarte con el Departamento de Comunicación e Imagen. Teléfono: 7737329100 ext 241 y 256. Correo: comunicacion@uttt.edu.mx. WhatsApp: 7736801596. Horario: lunes a viernes de 9:00 a 17:00.', 'aspirantes', true, '["no puedo registrar ficha uttt","problemas registro ficha uttt","error al registrar ficha uttt","no me deja sacar ficha uttt","no puedo hacer registro uttt","fallo registro ficha uttt","no funciona pagina ficha uttt","problema al registrarme uttt","no puedo hacer mi ficha uttt","error en plataforma uttt ficha","no carga pagina ficha uttt","problemas con registro en linea uttt","no puedo continuar registro uttt","falla registro admision uttt","error al llenar ficha uttt","no puedo completar registro uttt","problemas tecnicos ficha uttt","no puedo acceder registro uttt","error en preficha uttt","no puedo sacar ficha en linea uttt","fallo sistema admision uttt","problema registro universidad tula tepeji"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo hacer el registro de mi ficha desde mi celular?', 'Se recomienda utilizar una computadora para evitar errores en la captura de datos. Puedes acceder en: https://www.uttt.edu.mx/prefichas/', 'aspirantes', true, '["puedo usar celular para ficha uttt","registro ficha desde celular uttt","puedo hacer ficha en telefono uttt","registro ficha en movil uttt","puedo sacar ficha en celular uttt","registro admision celular uttt","puedo registrarme desde celular uttt","ficha en celular uttt","registro en telefono uttt ficha","puedo hacer preficha en celular uttt","ficha en movil uttt","registro en smartphone uttt","puedo usar celular para registro uttt","registro ficha desde telefono uttt","registro ficha movil uttt","puedo hacer ficha online en celular uttt","ficha desde celular es posible uttt","puedo registrarme en movil uttt","ficha en celular funciona uttt","registro admision movil uttt","puedo usar celular para preficha uttt","registro ficha por telefono uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Necesito tener un correo electrónico para registrarme?', 'Sí, deberás contar con un correo electrónico activo.', 'aspirantes', true, '["necesito correo para registrarme uttt","es obligatorio correo uttt","puedo registrarme sin correo uttt","correo necesario para ficha uttt","requieren email para registro uttt","puedo usar cualquier correo uttt","correo es obligatorio uttt","necesito email para admision uttt","puedo registrarme sin email uttt","correo para ficha uttt obligatorio","correo requerido uttt","email necesario para ficha uttt","correo para registro uttt","puedo usar correo falso uttt","correo valido para registro uttt","correo activo para ficha uttt","correo es necesario uttt","registro requiere correo uttt","email obligatorio uttt","correo para admision uttt","correo requerido para ficha uttt","necesito gmail para registrarme uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo puedo recuperar mi folio de registro?', 'Si olvidaste tu folio, puedes comunicarte con el Departamento de Comunicación e Imagen. Teléfono: 7737329100 ext 241 y 256. Correo: comunicacion@uttt.edu.mx. WhatsApp: 7736801596. Horario: lunes a viernes de 9:00 a 17:00.', 'aspirantes', true, '["recuperar folio uttt","olvide mi folio uttt","como saber mi folio uttt","no tengo mi folio uttt","perdi mi folio uttt","recuperar numero de registro uttt","folio admision perdido uttt","como obtener folio uttt","donde ver mi folio uttt","recuperar folio de ficha uttt","como buscar folio uttt","folio registro olvidado uttt","no recuerdo folio uttt","folio de admision uttt recuperar","como saber mi numero de folio uttt","folio extraviado uttt","como recuperar numero de folio uttt","donde recuperar folio uttt","folio perdido admision uttt","como consultar folio uttt","recuperar datos de registro uttt","folio preficha uttt recuperar"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si olvidé mi contraseña del registro?', 'Si olvidaste tu contraseña, puedes comunicarte con el Departamento de Comunicación e Imagen. Teléfono: 7737329100 ext 241 y 256. Correo: comunicacion@uttt.edu.mx. WhatsApp: 7736801596. Horario: lunes a viernes de 9:00 a 17:00.', 'aspirantes', true, '["olvide contraseña uttt","recuperar contraseña uttt","no recuerdo contraseña uttt","resetear contraseña uttt","recuperar acceso uttt","no puedo entrar sistema uttt","problema contraseña uttt","como recuperar password uttt","no puedo acceder cuenta uttt","recuperar clave uttt","olvide clave uttt","reset password uttt","problema login uttt","no puedo iniciar sesion uttt","recuperar acceso ficha uttt","contraseña perdida uttt","no recuerdo mi clave uttt","restablecer contraseña uttt","problema acceso uttt","recuperar cuenta uttt","no puedo entrar a preficha uttt","error contraseña uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo modificar mis datos después de haberme registrado?', 'La modificación de datos solo es posible durante el periodo habilitado para correcciones y depende de la disponibilidad de fichas. Para apoyo, contacta al Departamento de Comunicación e Imagen.', 'aspirantes', true, '["modificar datos uttt","cambiar datos registro uttt","editar registro uttt","corregir datos ficha uttt","puedo cambiar datos uttt","modificar informacion uttt","editar ficha uttt","cambiar informacion registro uttt","puedo corregir datos uttt","modificar registro admision uttt","editar datos admision uttt","corregir informacion uttt","cambiar datos personales uttt","modificar ficha uttt","editar preficha uttt","corregir registro uttt","puedo editar mis datos uttt","cambiar datos despues registro uttt","modificar informacion ficha uttt","editar datos registro uttt","cambiar informacion admision uttt","corregir datos admision uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si capturé mal mis datos en el registro?', 'Si capturaste datos incorrectos, puedes comunicarte con el Departamento de Comunicación e Imagen para recibir orientación y apoyo.', 'aspirantes', true, '["capture mal datos uttt","datos incorrectos registro uttt","error datos ficha uttt","me equivoque en registro uttt","datos mal capturados uttt","error en datos admision uttt","corregir datos mal uttt","datos incorrectos preficha uttt","error informacion uttt","captura incorrecta uttt","registro con error uttt","datos equivocados uttt","corregir informacion uttt","error datos personales uttt","captura mal hecha uttt","datos mal escritos uttt","registro incorrecto uttt","error en registro uttt","datos erroneos uttt","corregir datos admision uttt","error en preficha uttt","datos mal ingresados uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde puedo realizar el pago de mi ficha?', 'El pago de tu ficha puede realizarse en practicaja BBVA, Banco Bienestar o sistema Multipagos en línea con tarjeta.', 'aspirantes', true, '["donde pagar ficha uttt","pago ficha uttt donde","como pagar ficha uttt","donde hacer pago ficha uttt","formas de pago ficha uttt","pago admision uttt donde","donde pagar preficha uttt","como hacer pago ficha uttt","metodos de pago uttt ficha","donde deposito ficha uttt","pago en banco ficha uttt","pago en linea ficha uttt","donde pagar universidad tula tepeji ficha","como pagar admision uttt","pago multipagos uttt ficha","pago en bbva ficha uttt","pago banco bienestar ficha uttt","donde realizar pago uttt","pago ficha universidad uttt","donde pagar ficha admision uttt","formas de pago admision uttt","donde hacer pago universidad uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué pasa si no realizo el pago de la ficha a tiempo?', 'El formato de pago de tu ficha tiene una vigencia de tres días. Si no realizas el pago dentro de ese periodo, deberás generar uno nuevo en: https://www.uttt.edu.mx/prefichas/fReimpresionPreFicha.aspx. Para apoyo comunícate al 7737329100 ext 241 y 256 o al correo comunicacion@uttt.edu.mx.', 'aspirantes', true, '["no pague ficha uttt a tiempo","que pasa si no pago ficha uttt","vencio pago ficha uttt","se vencio ficha uttt","no hice pago ficha uttt","que pasa si vence ficha uttt","puedo pagar ficha despues uttt","ficha vencida uttt","no pague ficha que hago uttt","se cancela ficha uttt","pierdo ficha si no pago uttt","ficha expirada uttt","tiempo limite pago ficha uttt","no pague a tiempo uttt","que pasa si no pago preficha uttt","ficha caducada uttt","no pague ficha admision uttt","puedo recuperar ficha vencida uttt","que hacer si no pague ficha uttt","ficha sin pagar uttt","vencimiento ficha uttt","no pague ficha universidad uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Se puede pagar la ficha en línea?', 'Sí, siempre y cuando des clic en el botón Multipagos y cuentes con tarjeta de débito o crédito.', 'aspirantes', true, '["pago en linea ficha uttt","puedo pagar ficha online uttt","pago digital ficha uttt","pagar ficha por internet uttt","pago multipagos uttt","pagar ficha con tarjeta uttt","pago en linea admision uttt","puedo pagar ficha con tarjeta uttt","pago electronico ficha uttt","pago web ficha uttt","pago online universidad uttt","como pagar ficha en linea uttt","pago ficha con debito uttt","pago ficha con credito uttt","multipagos uttt ficha","pago virtual ficha uttt","puedo pagar ficha sin ir al banco uttt","pago ficha desde casa uttt","pago ficha internet uttt","pago ficha en sistema uttt","como pagar ficha digital uttt","pago ficha por web uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo pagar la ficha en ventanilla bancaria?', 'Sí, únicamente en Banco Bienestar. Para BBVA es por practicaja o transferencia bancaria.', 'aspirantes', true, '["pagar ficha en banco uttt","pago ventanilla uttt","puedo pagar ficha en banco uttt","donde pagar ficha banco uttt","pago ficha en banco bienestar uttt","pago ficha bbva uttt","pago ficha practicaja uttt","pago ficha transferencia uttt","pagar ficha en sucursal uttt","pago en ventanilla universidad uttt","pago fisico ficha uttt","pago presencial ficha uttt","pago ficha en banco como uttt","puedo pagar ficha en efectivo uttt","pago ficha banco como uttt","pago ficha banco bienestar uttt","pago ficha bbva practicaja uttt","donde pagar ficha en banco uttt","pago ficha en caja banco uttt","pago ficha en sucursal bancaria uttt","pago ficha universidad banco uttt","pago ficha presencial uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La ficha de admisión es transferible?', 'No, es personal e intransferible.', 'aspirantes', true, '["ficha es transferible uttt","puedo prestar mi ficha uttt","ficha se puede transferir uttt","puedo usar ficha de otra persona uttt","ficha es personal uttt","puedo ceder mi ficha uttt","ficha admision transferible uttt","puedo cambiar titular ficha uttt","ficha puede cambiar de dueño uttt","ficha es individual uttt","puedo compartir ficha uttt","ficha se puede vender uttt","ficha es unica uttt","ficha puede ser usada por otro uttt","ficha se puede cambiar uttt","ficha es intransferible uttt","puedo usar ficha ajena uttt","ficha pertenece a persona uttt","puedo modificar titular ficha uttt","ficha es solo para mi uttt","ficha no transferible uttt","ficha personal universidad uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo sacar ficha para más de una carrera?', 'No, solo puedes sacar ficha para una sola carrera.', 'aspirantes', true, '["puedo sacar dos fichas uttt","ficha para varias carreras uttt","puedo aplicar a dos carreras uttt","puedo elegir mas de una carrera uttt","ficha multiple carreras uttt","puedo registrarme en dos carreras uttt","puedo sacar ficha doble uttt","puedo elegir varias carreras uttt","ficha para varias opciones uttt","puedo aplicar a varias carreras uttt","puedo sacar ficha para dos carreras uttt","puedo tener dos fichas uttt","puedo aplicar a varias opciones uttt","puedo escoger varias carreras uttt","puedo registrarme en varias carreras uttt","ficha para multiples carreras uttt","puedo aplicar doble uttt","puedo tener varias opciones uttt","puedo registrar varias carreras uttt","puedo elegir mas de una opcion uttt","puedo hacer dos registros uttt","puedo aplicar a dos programas uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué documentos necesito para registrarme en el proceso de admisión?', 'Para obtener tu ficha no necesitas subir documentos. Para inscripción: acta de nacimiento, certificado o constancia, CURP, comprobante de domicilio y comprobante de pago.', 'aspirantes', true, '["documentos para registro uttt","que documentos piden uttt","requisitos documentos uttt","documentos para ficha uttt","que necesito para registrarme uttt","requisitos admision uttt documentos","papeles necesarios uttt","documentos ingreso uttt","documentos para inscripcion uttt","que papeles llevar uttt","documentos requeridos uttt","requisitos de documentos uttt","que documentos debo tener uttt","documentos universidad uttt","requisitos de papeles uttt","documentos necesarios admision uttt","que necesito para ficha uttt","documentos para entrar uttt","requisitos ingreso uttt documentos","papeles para admision uttt","documentos proceso admision uttt","requisitos universidad uttt documentos"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Necesito mi certificado de bachillerato para poder registrarme?', 'Sí, debes contar con tu certificado o una constancia de terminación.', 'aspirantes', true, '["necesito certificado bachillerato uttt","puedo registrarme sin certificado uttt","certificado obligatorio uttt","necesito certificado para ficha uttt","puedo usar constancia uttt","certificado requerido uttt","sin certificado puedo entrar uttt","necesito certificado preparatoria uttt","documento bachillerato uttt","puedo registrarme sin terminar prepa uttt","certificado o constancia uttt","requisito certificado uttt","certificado necesario uttt","puedo usar constancia de estudios uttt","certificado para admision uttt","documento de prepa uttt","certificado es obligatorio uttt","necesito documento de prepa uttt","puedo entrar sin certificado uttt","certificado o constancia admision uttt","requisito de prepa uttt","certificado preparatoria necesario uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo registrarme si aún no termino la preparatoria?', 'Sí, puedes registrarte, pero para inscribirte deberás contar con tu certificado o constancia.', 'aspirantes', true, '["puedo registrarme sin terminar prepa uttt","aun estudio prepa puedo entrar uttt","puedo registrarme sin acabar bachillerato uttt","terminando prepa puedo registrarme uttt","puedo hacer ficha sin terminar prepa uttt","aun no tengo certificado puedo registrarme uttt","puedo registrarme siendo estudiante uttt","puedo entrar sin terminar prepa uttt","registro sin terminar bachillerato uttt","puedo hacer examen sin terminar prepa uttt","puedo entrar aun estudiando prepa uttt","registro antes de terminar prepa uttt","puedo hacer ficha sin certificado uttt","registro anticipado uttt","puedo registrarme antes de graduarme uttt","puedo entrar siendo alumno de prepa uttt","puedo registrarme con constancia uttt","puedo aplicar sin terminar estudios uttt","puedo hacer proceso sin certificado uttt","registro sin concluir prepa uttt","puedo registrarme en proceso de prepa uttt","puedo aplicar aun en prepa uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Se requiere un promedio mínimo para ingresar a la UTTT?', 'No se requiere promedio mínimo, solo cumplir con el proceso de admisión.', 'aspirantes', true, '["promedio minimo uttt","necesito promedio para entrar uttt","cuanto promedio piden uttt","promedio requerido uttt","hay promedio minimo uttt","puedo entrar con bajo promedio uttt","promedio para admision uttt","requisito promedio uttt","promedio necesario uttt","cuanto promedio necesito uttt","promedio para universidad uttt","hay limite de promedio uttt","promedio para ingresar uttt","promedio obligatorio uttt","necesito buen promedio uttt","puedo entrar sin promedio alto uttt","promedio minimo admision uttt","promedio requerido universidad uttt","cuanto piden de promedio uttt","promedio importa uttt","requisito academico promedio uttt","promedio para entrar uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Existe un límite de edad para estudiar en la UTTT?', 'No existe límite de edad para estudiar en la UTTT.', 'aspirantes', true, '["hay limite de edad uttt","edad maxima uttt","puedo entrar siendo mayor uttt","edad para ingresar uttt","hay edad limite universidad uttt","puedo estudiar siendo adulto uttt","edad requerida uttt","hay edad maxima para entrar uttt","puedo entrar con mas edad uttt","edad minima o maxima uttt","puedo estudiar siendo mayor de edad uttt","edad importa para ingresar uttt","puedo entrar con cualquier edad uttt","edad limite universidad tula tepeji","hay restriccion de edad uttt","edad necesaria uttt","edad para estudiar uttt","puedo estudiar siendo grande uttt","edad para admision uttt","hay limite de edad universidad uttt","edad maxima para estudiar uttt","edad requisito uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');  

