INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Necesito presentar mi acta de nacimiento actualizada?', 'Sí, se recomienda presentar un acta reciente, legible y en buen estado.', 'aspirantes', true, '["acta nacimiento actualizada uttt","necesito acta reciente uttt","acta nacimiento obligatoria uttt","acta nacimiento requisito uttt","acta actualizada para inscripcion uttt","acta reciente necesaria uttt","documento acta nacimiento uttt","acta nacimiento vigente uttt","acta nacimiento para inscribirme uttt","acta nacimiento es obligatoria uttt","acta nacimiento en buen estado uttt","acta nacimiento legible uttt","acta nacimiento para admision uttt","acta nacimiento actual uttt","requisito acta nacimiento uttt","acta nacimiento universidad uttt","acta nacimiento para registro uttt","acta nacimiento para ingreso uttt","acta nacimiento documento requerido uttt","acta nacimiento importante uttt","acta nacimiento nueva uttt","acta nacimiento necesaria uttt"]'::jsonb, 'Brenda Magaly Arguelles Trillo', 'Jefe (a) de departamento', 'Departamento de Ingreso y Captación');

