INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde está el edificio de Contaduría en la UTTT?','El edificio de Contaduría se ubica en la zona central izquierda, cerca de la biblioteca, cafetería y Unidad de Docencia. Mapa: https://www.uttt.edu.mx/Micrositio/croquis/ Si necesitas ubicar otro edificio, puedo ayudarte.','general',true,'["contaduria uttt edificio","donde esta contaduria uttt","ubicacion contaduria uttt","mapa contaduria uttt","contaduria campus uttt","contador edificio uttt","contaduria universidad uttt","ubicacion contaduria campus tula","mapa campus contaduria uttt","contaduria biblioteca uttt","contaduria cafeteria uttt","contaduria docencia uttt","donde encontrar contaduria uttt","ubicacion contaduria universidad uttt","mapa universidad contaduria uttt","contaduria campus central uttt","area contabilidad uttt","edificio contabilidad uttt","contaduria informacion uttt","contador campus uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  

-- ID 200
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde está Control Escolar?','Control Escolar se encuentra dentro del campus Tula-Tepeji de la UTTT. En el mapa está dentro del edificio UD3, en la zona central, cerca de la biblioteca y la cafetería. Mapa: https://www.uttt.edu.mx/Micrositio/croquis/ Si necesitas ubicar otra área, puedo ayudarte.','ubicaciones_internas',true,'["control escolar uttt","donde esta control escolar uttt","ubicacion control escolar uttt","mapa control escolar uttt","control escolar ud3 uttt","control escolar campus uttt","oficina control escolar uttt","tramites escolares uttt","control escolar universidad uttt","ubicacion control escolar campus tula","mapa campus control escolar uttt","control escolar biblioteca uttt","control escolar cafeteria uttt","control escolar ud3 ubicacion","donde encontrar control escolar uttt","ubicacion control escolar universidad uttt","mapa universidad control escolar uttt","control escolar campus central uttt","area control escolar uttt","control escolar informacion uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 201
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde está el servicio médico?','El servicio médico se encuentra dentro del campus Tula-Tepeji de la UTTT. En el mapa aparece como "Servicio Médico", en la zona inferior izquierda, cerca de Vinculación, Rectoría y UD3. Mapa: https://www.uttt.edu.mx/Micrositio/croquis/ Si necesitas ubicar otra área, puedo ayudarte.','ubicaciones_internas',true,'["servicio medico uttt","medico uttt","donde esta servicio medico uttt","ubicacion medico uttt","mapa servicio medico uttt","salud uttt","enfermeria servicio uttt","atencion medica uttt","medico campus uttt","servicio medico universidad uttt","ubicacion medico campus tula","mapa campus medico uttt","medico vinculacion uttt","medico rectoria uttt","medico ud3 uttt","donde encontrar medico uttt","ubicacion servicio medico universidad uttt","mapa universidad medico uttt","servicio medico campus central uttt","medico informacion uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 202
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde está Gastronomía?','El edificio de Gastronomía se encuentra dentro del campus Tula-Tepeji de la UTTT. En el mapa aparece como "Gastronomía", en la parte inferior central, cerca de Rectoría, Vinculación y las villas. Mapa: https://www.uttt.edu.mx/Micrositio/croquis/ Si necesitas ubicar otro edificio, puedo ayudarte.','ubicaciones_internas',true,'["gastronomia uttt edificio","donde esta gastronomia uttt","ubicacion gastronomia uttt","mapa gastronomia uttt","gastronomia campus uttt","chef uttt edificio","gastronomia universidad uttt","ubicacion gastronomia campus tula","mapa campus gastronomia uttt","gastronomia rectoria uttt","gastronomia vinculacion uttt","gastronomia villas uttt","donde encontrar gastronomia uttt","ubicacion gastronomia universidad uttt","mapa universidad gastronomia uttt","gastronomia campus central uttt","area cocina uttt","edificio cocina uttt","gastronomia informacion uttt","carrera gastronomia edificio uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 203
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde está la cafetería?','La cafetería se encuentra dentro del campus Tula-Tepeji de la UTTT. En el mapa aparece como "Cafetería", en la zona central izquierda, cerca de la biblioteca, la Unidad de Docencia y Contaduría. Mapa: https://www.uttt.edu.mx/Micrositio/croquis/ Si necesitas ubicar otra área, puedo ayudarte.','ubicaciones_internas',true,'["cafeteria uttt","donde esta cafeteria uttt","ubicacion cafeteria uttt","mapa cafeteria uttt","comedor uttt","cafeteria campus uttt","comida uttt","cafeteria universidad uttt","ubicacion cafeteria campus tula","mapa campus cafeteria uttt","cafeteria biblioteca uttt","cafeteria docencia uttt","cafeteria contaduria uttt","donde encontrar cafeteria uttt","ubicacion cafeteria universidad uttt","mapa universidad cafeteria uttt","cafeteria campus central uttt","area comida uttt","comedor universitario uttt","cafeteria informacion uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');


-- ID 204
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('El asistente no me ayuda','Lamento el inconveniente. Actualmente estoy en proceso de entrenamiento, por lo que algunas respuestas pueden no ser completamente precisas. Puedes reformular tu pregunta y con gusto intentaré ayudarte nuevamente. También puedes comunicarte con el departamento de Comunicación: Teléfono: 773 732 9100 ext. 241 y 256 | Correo: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario: Lunes a viernes de 9:00 a 17:00 horas.','soporte',true,'["no me ayudas","no me ayudaste","no ayudas","no sirves","no me sirves","no sirves para nada","no me sirvio","no sirvio","esto no sirve","no funciona","no eres util","eres inutil","no haces nada","no ayudas en nada","no resolviste nada","no me resolviste nada","no me diste respuesta","no contestaste bien","no respondes bien","no entiendes","esto esta mal","estas mal","estas equivocado","tu respuesta esta mal","no es correcto","eso no es lo que pedi","no es lo que pregunte","no me entendiste","no sirve tu respuesta","esto no me ayuda","no jalas","no rifas","no sirves bro","no me ayudas bro","no me sirves bro","vales para nada","no vales","no das una","estas bien mal","no sabes nada","no me ayuda","no me sirvio esto","esto no me sirvio","no funciona esto","no sirve esto","no responde bien","no esta bien","no esta correcto","no ayuda esto","no me sirve esto","me estas dando mal la info","no me diste lo que pedi","no es la respuesta que queria","no me resolviste mi duda","no me ayudaste con mi problema","no esta bien tu respuesta","tu respuesta no me sirve","no me funciona esto","no me sirve tu ayuda","no me diste informacion correcta","esto esta mal explicado","no explicas bien","no ayudas en esto","no sirve este bot","este bot no sirve","no funciona este bot","no es util este bot","no ayuda este bot","no me sirve el bot","no me ayuda el bot","no mames no ayudas","vales pura madre","no