-- ID 205
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Quién desarrolló este asistente virtual?','Este asistente virtual fue desarrollado por un equipo de la carrera de Tecnologías de la Información de la UTTT. Equipo de desarrollo: Ing. Hugo Adrián Mercado González, Ing. Emmanuel Calva Ocampo. Soporte: Ing. Saúl Eliel Pérez Pérez. Colaboración académica: Dra. Margarita Núñez Zamudio. Dirección de Tecnologías de la Información: Ing. Hugo David Calva Ramírez. Apoyo técnico: Ing. Erik Guerrero Bravo. Este proyecto fue realizado como parte del desarrollo tecnológico institucional en el año 2026.','general',true,'["quien desarrollo este asistente","quien creo este asistente","quien hizo este asistente","quien desarrollo este chatbot","quien creo este chatbot","quien esta detras de este asistente","quien es el creador de este asistente","quien desarrollo este sistema","quien creo este sistema","quien hizo este sistema","quien te creo","quien te hizo","quien te desarrollo","quien te programo","quien es tu creador","quien es tu padre","quien eres","quien te hizo","quien te creo","quien te desarrollo","quien creo este asistente","quien hizo este chatbot","quien esta detras de este asistente","quien es tu creador","quien es tu padre","quien te programo","quien desarrollo este sistema","quien creo este sistema","quien hizo este sistema","quien hizo este asistente virtual","quien hizo este bot","quien creo este bot","quien programo este bot","quien hizo este chat","quien creo este chat","quien desarrollo este chat","quien esta detras de este bot","quien hizo este sistema","quien programo este sistema","quien creo este sistema virtual"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  

-- ID 206
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si ya pagué mi ficha y no se refleja en el sistema?','Si ya realizaste tu pago y aún no se refleja en el sistema, puede deberse a un tiempo de procesamiento. Te recomendamos esperar un momento y verificar nuevamente. Si el problema persiste, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o al Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx. También puedes acudir de manera presencial en un horario de lunes a viernes de 9:00 a 17:00 horas. El Departamento de Ingreso y Captación se encuentra en el edificio de Vinculación (marcado como "Vinculación" en el croquis), mientras que el Departamento de Sistemas se ubica en el área de Rectoría (marcado como "Rectoría"). Puedes consultar el mapa del campus aquí: https://www.uttt.edu.mx/Micrositio/croquis/','aspirantes',true,'["ya pague y no se refleja","ya pague y no aparece","no se refleja mi pago","pague y no sale en sistema","mi pago no aparece","ya hice el pago y no aparece","pague mi ficha y no se ve","no se registra mi pago","ya pague pero no sale","mi pago no se refleja","pague y no se actualiza","no aparece mi pago en la plataforma","ya pague y no se registra","el sistema no reconoce mi pago","pague y sigue pendiente","mi pago sigue pendiente","ya hice el deposito y no aparece","no se ve reflejado el pago","pague pero no cambia el estatus","mi pago no se actualiza en el sistema"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 207
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Por qué mi pago aparece como no registrado si ya pagué?','Si tu pago aparece como no registrado, es probable que aún se encuentre en proceso de validación en el sistema. Te recomendamos esperar un poco y volver a consultar tu estatus. Si el problema continúa, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o al Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx. También puedes acudir de manera presencial en un horario de lunes a viernes de 9:00 a 17:00 horas. El Departamento de Ingreso y Captación se encuentra en el edificio de Vinculación (marcado como "Vinculación" en el croquis), mientras que el Departamento de Sistemas se ubica en el área de Rectoría (marcado como "Rectoría"). Puedes consultar el mapa del campus aquí: https://www.uttt.edu.mx/Micrositio/croquis/','aspirantes',true,'["mi pago aparece no registrado","pago no registrado","ya pague y dice no registrado","mi pago sale como no registrado","pague pero aparece no registrado","por que dice no registrado mi pago","no registrado el pago","mi pago no esta registrado","pago sin registrar sistema","ya hice el pago y no esta registrado","pague y sigue no registrado","el sistema dice no registrado","pago no reconocido","no reconoce mi pago","mi pago no esta validado","pago pendiente de validar","mi pago no se valida","pago no confirmado sistema","ya pague y sigue no registrado","no se registra mi pago en sistema"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 208
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Me pueden ayudar a hacer mi registro de admisión?','Sí, puedes realizar tu registro siguiendo estos pasos: 1) Ingresa al portal https://www.uttt.edu.mx/prefichas/ 2) Genera tu formato de pago. 3) Realiza el pago en practicaja BBVA o mediante Multipagos con tarjeta. 4) Espera un día hábil para que el pago se refleje. 5) Ingresa nuevamente con tu usuario y contraseña. 6) Completa tu registro en línea. 7) Descarga tu pase de ingreso donde se indica fecha, hora y lugar de tu evaluación. 8) Descarga la guía de estudio desde el mismo portal. Si tienes dudas o necesitas apoyo, puedes comunicarte al Departamento de Ingreso y Captación al correo comunicacion@uttt.edu.mx o acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx. También puedes acudir de manera presencial en un horario de lunes a viernes de 9:00 a 17:00 horas. El Departamento de Ingreso y Captación se encuentra en el edificio de Vinculación (marcado como "Vinculación" en el croquis), mientras que el Departamento de Sistemas se ubica en el área de Rectoría (marcado como "Rectoría"). Puedes consultar el mapa del campus aquí: https://www.uttt.edu.mx/Micrositio/croquis/','aspirantes',true,'["me ayudan a registrarme","pueden ayudarme a hacer mi registro","necesito ayuda para registrarme","me puedes ayudar a hacer mi registro","como me registro con ayuda","alguien me ayuda con mi registro","ayuda para hacer mi registro","no se como registrarme me ayudan","me apoyan con el registro","quiero ayuda para registrarme","quien me ayuda a registrarme","pueden apoyarme con mi registro","necesito apoyo para registrarme","ayuda con el proceso de registro","no entiendo el registro me ayudan","me orientan para registrarme","como hago mi registro con ayuda","me pueden guiar en mi registro","quiero que me ayuden a registrarme","ayuda para sacar mi ficha"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 209
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo puedo saber a qué hora me toca mi examen de admisión?','La fecha y hora de tu examen de admisión vienen indicadas en tu pase de ingreso al examen. Te recomendamos revisar cuidadosamente tu ficha descargada desde el portal de aspirantes. Si tienes alguna duda, puedes comunicarte con el Departamento de Comunicación e Imagen para que te orienten: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["a que hora es mi examen","como saber hora de mi examen","que hora me toca examen","hora del examen uttt","cuando es mi examen hora","como ver hora de examen","donde veo mi hora de examen","mi examen a que hora es","como saber fecha y hora de examen","hora examen admision","cuando me toca examen horario","hora de evaluacion diagnostica","cuando es mi examen uttt","como saber mi horario de examen","donde viene la hora del examen","mi pase de ingreso que hora dice","como consultar hora de examen","cuando es mi examen y a que hora","hora examen ficha uttt","horario examen admision uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación'); 

-- ID 210
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuándo es el examen de admisión de la UTTT?','La fecha de tu examen de admisión se indica en tu pase de ingreso al examen. Te recomendamos revisar tu ficha descargada desde el portal de aspirantes para conocer la fecha, hora y lugar asignados. Para dudas y aclaraciones, puedes comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["cuando es el examen de admision","fecha del examen uttt","cuando es mi examen","que dia es el examen uttt","cuando toca el examen de admision","fecha examen diagnostico uttt","cuando es evaluacion diagnostica","que dia presento examen uttt","cuando se presenta el examen uttt","cuando es el examen de ingreso","fecha examen ficha uttt","cuando me toca el examen","cuando es examen uttt 2026","fecha del examen de ingreso uttt","cuando es la prueba de admision","cuando es examen universidad uttt","fecha examen aspirantes uttt","cuando se hace el examen uttt","que fecha es el examen uttt","cuando es el examen para entrar a la uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 211
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuándo cierra la convocatoria de admisión de la UTTT?','La convocatoria de ingreso comprende del 02 de marzo de 2026 al 07 de julio de 2026. Te recomendamos realizar tu proceso dentro de este periodo para asegurar tu participación. Para dudas y aclaraciones, puedes comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["cuando cierra la convocatoria","fecha limite convocatoria uttt","hasta cuando hay convocatoria","cuando termina la convocatoria","cuando se cierra convocatoria uttt","fecha de cierre convocatoria","hasta que dia puedo registrarme","cuando acaba convocatoria admision","ultimo dia convocatoria uttt","cuando finaliza convocatoria","cuando termina el registro uttt","hasta cuando puedo sacar ficha","fecha limite para ficha uttt","cuando se acaba la convocatoria","hasta cuando puedo aplicar uttt","fecha final de convocatoria","cuando es el cierre de admision","cuando acaba el proceso de admision","cuando termina el registro de aspirantes","cuando cierra admision uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');


-- ID 212
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde puedo obtener el formato o la referencia de pago de mi ficha de admisión?','El costo de la ficha de admisión es de $333.00 MXN (trescientos treinta y tres pesos 00/100 M.N.). Para obtener el formato de pago, debes ingresar al portal https://www.uttt.edu.mx/Prefichas/fCampus.aspx, seleccionar el campus donde deseas realizar tu proceso (Tula-Tepeji, Chapulhuacán o Tepetitlán) y completar cuidadosamente el formulario de datos personales. Posteriormente, deberás llenar el formulario de contacto y continuar con el proceso para generar tu formato de pago. Una vez realizado el pago, deberás dirigirte al siguiente enlace https://www.uttt.edu.mx/paseexamen/login.aspx e ingresar con el usuario y contraseña que te hayan asignado para obtener tu pase de ingreso a la evaluación diagnóstica. Si tienes alguna duda o presentas algún inconveniente, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o al Departamento de Ingreso y Captación: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596. También puedes acudir de manera presencial en un horario de lunes a viernes de 9:00 a 17:00 horas.','aspirantes',true,'["donde saco el formato de pago","como obtener referencia de pago","donde obtengo la ficha de pago","como generar formato de pago uttt","donde saco referencia de pago","como consigo el formato de pago","donde puedo pagar la ficha uttt","como obtener ficha de pago","como sacar referencia de pago uttt","donde encuentro el formato de pago","como generar mi pago uttt","donde obtengo el pago de ficha","como obtener el recibo de pago","donde viene la referencia de pago","como hacer el pago de ficha uttt","como consigo la referencia uttt","donde genero mi pago uttt","como obtener datos para pagar ficha","donde saco mi ficha de pago uttt","como generar el pago de admision"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 213
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué pasa si mi fecha de pago ya venció?','Si la fecha de pago de tu ficha ha vencido, deberás volver a generar o reimprimir tu formato de pago ingresando con tu usuario y contraseña en el siguiente enlace: https://www.uttt.edu.mx/prefichas/fReimpresionPreFicha.aspx. Desde ahí podrás obtener nuevamente tu referencia para realizar el pago y continuar con tu proceso de admisión. Si tienes alguna duda o presentas algún inconveniente, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["mi pago vencio","se vencio mi pago","fecha de pago vencida","que hago si mi pago vencio","ya no puedo pagar mi ficha","se paso la fecha de pago","mi ficha esta vencida","puedo pagar despues de la fecha","se vencio la referencia de pago","como renovar mi pago","como reimprimir mi ficha de pago","mi formato de pago vencio","no pague a tiempo","que pasa si no pague a tiempo","puedo volver a generar mi pago","como sacar otra referencia de pago","como recuperar mi formato de pago","pago expirado que hago","mi pago ya no es valido","como generar nuevo pago uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 214
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si no puedo generar mi ficha de admisión?','Si tienes problemas para generar tu ficha de admisión, te recomendamos verificar que estés ingresando correctamente tus datos y que tu conexión a internet sea estable. También puedes intentar realizar el proceso desde otro navegador o dispositivo. Si el problema persiste, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["no puedo generar mi ficha","no me deja sacar mi ficha","error al generar ficha","no puedo hacer mi registro ficha","no carga la pagina de ficha","no puedo sacar ficha uttt","problema al generar ficha","no me deja registrarme ficha","error en prefichas uttt","no funciona la pagina de registro","no puedo completar mi registro","la pagina no sirve ficha","no puedo avanzar en registro","error al sacar ficha uttt","no genera mi ficha","no puedo hacer mi ficha de admision","problema con el registro uttt","no me deja continuar registro","falla al generar ficha","no puedo iniciar registro ficha"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');


-- ID 215
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si no puedo iniciar sesión en el sistema?','Si tienes problemas para iniciar sesión en el sistema, verifica que estés ingresando correctamente tu usuario y contraseña, respetando mayúsculas y minúsculas. También puedes intentar acceder desde otro navegador o dispositivo. Si el problema persiste, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["no puedo iniciar sesion","no puedo entrar al sistema","no me deja iniciar sesion","error al iniciar sesion","no puedo acceder a mi cuenta","no me deja entrar al portal","no funciona mi usuario","no acepta mi contraseña","problema para iniciar sesion","no puedo entrar a prefichas","no puedo entrar a pase de examen","no puedo acceder al sistema uttt","mi cuenta no funciona","no puedo logearme","error de login uttt","no reconoce mi usuario","no puedo ingresar al portal uttt","no abre mi cuenta","problema con acceso uttt","no puedo entrar a mi perfil"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');


-- ID 216
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si olvidé mi usuario o contraseña?','Si olvidaste tu usuario o contraseña, te recomendamos revisar tu correo electrónico donde se te proporcionaron tus datos de acceso al momento de registrarte. En caso de no encontrarlos o no poder recuperar el acceso, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["olvide mi contraseña","olvide mi usuario","no recuerdo mi contraseña","no recuerdo mi usuario","como recuperar mi contraseña","como recuperar mi usuario","no puedo entrar porque olvide mi contraseña","olvide mis datos de acceso","recuperar acceso uttt","no tengo mi usuario","no tengo mi contraseña","como recuperar mi cuenta uttt","olvide mis datos de login","no recuerdo mis datos de registro","perdi mi contraseña uttt","no puedo acceder porque olvide datos","olvide mis credenciales","no se mi usuario ni contraseña","recuperar cuenta prefichas","no encuentro mis datos de acceso"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');


-- ID 217
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si tengo dudas al llenar mis datos en el registro de admisión?','Si tienes dudas al llenar tus datos en el registro, puedes guiarte de la siguiente manera: 1) Ingresa tu nombre, apellido paterno y apellido materno tal como aparecen en tu acta de nacimiento. 2) Selecciona tu género. 3) Indica tu nacionalidad. 4) Selecciona tu país de nacimiento. 5) Elige el estado y municipio donde naciste. 6) Captura tu fecha de nacimiento en formato día/mes/año. 7) Ingresa tu CURP correctamente, ya que el sistema puede validarla automáticamente. Es importante llenar todos los campos obligatorios (*) con información verídica. Antes de continuar, revisa cuidadosamente que todos tus datos sean correctos para evitar errores en tu proceso. Si tienes alguna duda o presentas algún inconveniente, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["como llenar el registro","como llenar datos personales uttt","que poner en el registro","como llenar el formulario de admision","duda en datos personales","no se como llenar mis datos","ayuda para llenar registro","como capturar mis datos correctamente","que datos debo ingresar en el registro","no entiendo el formulario de datos","como llenar la ficha paso a paso","duda con CURP en registro","como llenar datos de nacimiento","no se que poner en genero nacionalidad","como llenar el registro correctamente","ayuda con datos personales ficha","como llenar formulario prefichas","duda en campos obligatorios","no entiendo como llenar la ficha","explicame como llenar el registro"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 218
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Dónde puedo descargar mi pase de ingreso al examen?','Para descargar tu pase de ingreso al examen, debes ingresar al siguiente enlace: https://www.uttt.edu.mx/paseexamen/login.aspx e iniciar sesión con el usuario y contraseña que te fueron asignados durante tu registro. Una vez dentro del sistema, podrás descargar tu pase, donde se indica la fecha, hora y lugar de tu evaluación diagnóstica. Si tienes alguna duda o presentas algún inconveniente, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["donde descargo mi pase de examen","como descargar pase de ingreso","donde ver mi pase de examen","como obtener mi pase de examen","no encuentro mi pase de ingreso","donde saco mi pase de evaluacion","como ver mi pase de examen uttt","descargar pase de examen uttt","donde ver fecha de examen uttt","como consultar mi pase de ingreso","no tengo mi pase de examen","donde veo mi examen uttt","como obtener pase de evaluacion","pase de ingreso donde esta","como acceder a mi pase de examen","donde consultar mi examen","como descargar ficha de examen","donde ver mi horario de examen","pase de examen uttt login","como ver mi evaluacion diagnostica"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 219
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué debo llevar el día de mi examen de admisión?','El día de tu evaluación diagnóstica deberás presentar tu pase de ingreso impreso y una identificación oficial o credencial con fotografía. Además, se recomienda llevar lápiz, hojas blancas y una calculadora básica. Te sugerimos llegar con anticipación al lugar indicado en tu pase para evitar contratiempos. Si tienes alguna duda o presentas algún inconveniente, puedes comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["que llevar al examen uttt","que necesito para el examen","que debo llevar al examen de admision","material para examen uttt","requisitos dia del examen","que llevar evaluacion diagnostica","que necesito el dia del examen","documentos para examen uttt","que llevar al pase de examen","que debo presentar en el examen","que cosas llevar al examen","necesito calculadora examen uttt","puedo llevar hojas al examen","que me piden en el examen uttt","material permitido examen uttt","que llevar para evaluacion diagnostica","documentos para pase de ingreso","que llevar dia de evaluacion","requisitos para examen de admision","que necesito para presentar examen uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 220
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿A quién corresponde el estado civil que se solicita en el registro?','El estado civil que se solicita en el registro corresponde al aspirante, es decir, a la persona que está realizando el proceso de admisión. Te recomendamos capturar esta información de manera correcta junto con tus demás datos personales para evitar errores en tu registro. Si tienes alguna duda o presentas algún inconveniente, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["estado civil de quien es","el estado civil es del alumno o padre","a quien corresponde estado civil","que pongo en estado civil registro","estado civil del aspirante o tutor","duda estado civil ficha","el estado civil es mio o de mis papas","que significa estado civil en registro","quien llena estado civil","estado civil a quien pertenece","duda campo estado civil","que pongo en estado civil uttt","estado civil es del estudiante","campo estado civil a quien corresponde","como llenar estado civil registro","estado civil del alumno o tutor","que significa estado civil en ficha","estado civil registro admision","duda con estado civil formulario","estado civil en prefichas uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  

-- ID 221
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si capturé mal mis datos en el registro de admisión?','Si capturaste incorrectamente algún dato durante tu registro, te recomendamos revisar si aún puedes corregirlo dentro del sistema antes de finalizar tu proceso. En caso de que ya no sea posible modificar la información, será necesario que te comuniques para recibir apoyo. Puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["capture mal mis datos","ingrese mal mis datos","me equivoque en el registro","como corregir mis datos","error en mis datos personales","puse mal mi informacion","como cambiar mis datos registro","me equivoque en mi ficha","datos incorrectos en registro","como modificar mis datos uttt","error al capturar datos","como corregir informacion registro","puse mal mi nombre en registro","error en datos de ficha","como actualizar mis datos registro","equivocacion en datos personales","como arreglar mis datos uttt","modificar datos de admision","corregir informacion de ficha","datos mal capturados"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 222
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si ingresé mal mi correo electrónico o número telefónico?','Si ingresaste incorrectamente tu correo electrónico o número telefónico durante el registro, no te preocupes, es una situación que puede resolverse. Te recomendamos verificar si aún puedes corregirlo dentro del sistema antes de finalizar tu proceso. En caso de que ya no sea posible modificarlo, será necesario que te comuniques para recibir apoyo. Puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["puse mal mi correo","puse mal mi numero","correo incorrecto registro","numero incorrecto registro","me equivoque en mi correo","me equivoque en mi telefono","como cambiar mi correo uttt","como cambiar mi numero registro","no me llegan correos","no me llegan mensajes","error en correo registro","error en telefono registro","no recibi informacion uttt","correo mal capturado","telefono mal capturado","no me llega mi usuario","no recibi datos de acceso","correo equivocado ficha","numero equivocado ficha","no recibo informacion del proceso"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 223
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si no recibí información del proceso de admisión?','Si no has recibido información sobre tu proceso de admisión, no te preocupes, es una situación que puede resolverse. Te recomendamos revisar tu bandeja de entrada, incluyendo la carpeta de spam o correo no deseado, y verificar que tu correo electrónico y número telefónico estén correctamente registrados. Si después de esto no has recibido información, puedes comunicarte para recibir apoyo. Puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["no recibi informacion","no me llego informacion","no me llega nada","no recibi correo uttt","no me llego mi ficha","no recibi datos de acceso","no me llega informacion del proceso","no me llego correo de registro","no recibi notificaciones","no me llego mi usuario","no me llego mi contraseña","no tengo informacion de admision","no me llego mensaje uttt","no recibo correos uttt","no me llega el pase de examen","no me llega informacion de registro","no tengo noticias de mi proceso","no me llego confirmacion","no recibi informacion de mi ficha","no me llega nada del proceso"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');


-- ID 224
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si mi CURP no es aceptada en el sistema?','Si tu CURP no es aceptada en el sistema, te recomendamos verificar que esté correctamente capturada, sin espacios y con el formato oficial. Asegúrate de que coincida exactamente con la información de tus documentos oficiales. Si el problema persiste, puede deberse a que tu CURP no esté actualizada en el sistema nacional. En ese caso, puedes intentar nuevamente más tarde o comunicarte para recibir apoyo. Puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["mi curp no funciona","curp no valida","no acepta mi curp","error con mi curp","mi curp es incorrecta","no puedo ingresar mi curp","problema con curp registro","curp invalida sistema","no reconoce mi curp","curp no registrada","error al capturar curp","mi curp no pasa","no valida curp uttt","curp no aceptada registro","no puedo continuar por curp","curp incorrecta sistema","problema con curp uttt","no reconoce curp sistema","curp no valida en prefichas","error curp admision"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');


-- ID 225
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué pasa si ya me registré y quiero volver a hacerlo?','Si ya realizaste tu registro, no es necesario volver a hacerlo, ya que cada aspirante debe contar con un único registro en el sistema. Si intentas registrarte nuevamente, podrías generar duplicidad de información y afectar tu proceso de admisión. Si necesitas corregir algún dato o presentar algún inconveniente con tu registro, puedes comunicarte para recibir apoyo. Puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["ya me registre y quiero hacerlo otra vez","puedo registrarme dos veces","registro duplicado uttt","ya hice registro puedo repetirlo","quiero volver a registrarme","hice mal mi registro puedo hacerlo de nuevo","puedo tener dos registros","registro doble uttt","volver a hacer registro admision","ya tengo registro puedo hacer otro","como eliminar mi registro uttt","quiero registrarme otra vez","registro duplicado que hago","puedo repetir mi registro","ya hice mi ficha puedo hacer otra","error en registro quiero repetir","registro repetido admision","puedo rehacer mi registro uttt","ya me registre pero quiero cambiar datos","duplicidad de registro uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  

-- ID 226
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué pasa si no puedo asistir al examen de admisión?','Si no puedes asistir a tu evaluación diagnóstica en la fecha programada, te recomendamos comunicarte lo antes posible con el Departamento de Comunicación e Imagen para informar tu situación. El área correspondiente revisará tu caso y te indicará si existe la posibilidad de reprogramar tu evaluación. Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["no puedo ir al examen","no podre asistir al examen","no puedo presentar examen","que hago si falto al examen","no puedo asistir evaluacion","no puedo ir el dia del examen","no podre presentar examen uttt","que pasa si no voy al examen","puedo faltar al examen","no puedo asistir a evaluacion diagnostica","no podre ir a mi examen","no puedo asistir en mi fecha","que hago si no voy al examen","no podre asistir evaluacion uttt","no puedo presentar mi examen","falta al examen admision","no puedo ir a presentar examen","que pasa si no presento examen","no puedo acudir al examen","no puedo asistir a mi examen"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 227
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo cambiar la fecha de mi examen de admisión?','El cambio de fecha para la evaluación diagnóstica sólo puede realizarse en casos justificados. Te recomendamos comunicarte con el Departamento de Comunicación e Imagen para revisar tu situación y conocer si es posible realizar una reprogramación. Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["puedo cambiar fecha examen","cambiar fecha evaluacion","reprogramar examen uttt","puedo cambiar mi examen","cambiar dia de examen","reprogramar evaluacion diagnostica","puedo mover mi examen","cambiar fecha de evaluacion","reprogramar fecha examen","puedo cambiar el dia de examen","cambiar horario examen","reprogramar examen admision","puedo cambiar fecha de mi examen","mover fecha de examen","puedo reagendar examen","cambiar dia evaluacion","reprogramar evaluacion uttt","puedo cambiar fecha evaluacion","cambiar examen de dia","puedo cambiar mi fecha de examen"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 228
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué recomendaciones debo seguir para mi proceso de admisión?','Te recomendamos leer cuidadosamente la convocatoria, completar tu registro con datos correctos, realizar tu pago en tiempo y forma, y revisar constantemente tu correo electrónico y el portal de aspirantes para dar seguimiento a tu proceso. Asimismo, prepara con anticipación tu evaluación diagnóstica y conserva tus datos de acceso. Ante cualquier duda, puedes comunicarte con el Departamento de Comunicación e Imagen.','aspirantes',true,'["recomendaciones admision","que debo hacer para admision","tips para admision uttt","como prepararme para admision","consejos proceso admision","que hacer en mi proceso","recomendaciones para ficha","como llevar mi proceso correctamente","tips para examen uttt","que debo considerar admision","como hacer bien mi registro","consejos registro uttt","como prepararme evaluacion","recomendaciones proceso uttt","tips aspirantes uttt","que hacer para no fallar","como completar proceso admision","recomendaciones ficha uttt","tips proceso aspirante","consejos admision uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 229
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo cambiar de carrera después de registrarme?','El cambio de carrera puede estar sujeto a disponibilidad de espacios y al estado de tu proceso de admisión. Te recomendamos comunicarte con el Departamento de Comunicación e Imagen para recibir orientación sobre tu caso específico.','aspirantes',true,'["puedo cambiar de carrera","cambiar carrera uttt","me equivoque de carrera","quiero cambiar mi carrera","modificar carrera registro","cambio de carrera admision","puedo elegir otra carrera","cambiar opcion carrera","equivocacion de carrera","quiero otra carrera uttt","modificar carrera ficha","cambiar programa educativo","puedo cambiar opcion academica","corregir carrera seleccionada","cambiar carrera despues registro","modificar opcion de carrera","cambiar seleccion de carrera","puedo cambiar mi opcion","error en carrera elegida","cambiar carrera en registro"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 230
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo cambiar de campus después de registrarme?','El cambio de campus puede depender de la disponibilidad y del avance de tu proceso de admisión. Te recomendamos comunicarte con el Departamento de Comunicación e Imagen para revisar tu caso y recibir orientación.','aspirantes',true,'["cambiar de campus","puedo cambiar campus","me equivoque de campus","cambiar campus uttt","modificar campus registro","cambio de campus admision","puedo elegir otro campus","cambiar sede uttt","equivocacion campus","quiero cambiar de campus","modificar campus ficha","cambiar campus despues registro","puedo cambiar sede","error en campus seleccionado","cambiar campus proceso","modificar campus admision","cambiar lugar de estudio","puedo cambiar campus uttt","cambiar opcion campus","error campus registro"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 231
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué pasa si no termino mi registro de admisión?','Si no completas tu registro de admisión, tu proceso quedará inconcluso y no podrás continuar con las siguientes etapas. Te recomendamos ingresar nuevamente al sistema y finalizar tu registro para generar tu formato de pago y continuar con tu proceso.','aspirantes',true,'["no termine mi registro","registro incompleto","no acabe mi ficha","no finalize mi registro","que pasa si no termino registro","registro pendiente uttt","no complete mi ficha","deje incompleto registro","no termine preficha","registro sin finalizar","no acabe proceso registro","registro a medias uttt","no complete datos registro","proceso incompleto admision","no termine mi ficha uttt","registro no finalizado","no acabe mi proceso","registro incompleto que hago","no finalize mi proceso","registro sin terminar"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 232
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuánto tiempo tarda en reflejarse mi pago?','El tiempo en que se refleja tu pago puede variar dependiendo del método utilizado, pero generalmente se ve reflejado en un periodo corto. Te recomendamos esperar un momento y verificar nuevamente en el sistema. Si el problema persiste, puedes comunicarte con el área correspondiente para recibir apoyo.','aspirantes',true,'["cuanto tarda en reflejarse pago","tiempo de validacion pago","cuanto tarda pago uttt","cuando se refleja mi pago","tiempo reflejo pago","cuanto tarda en actualizar pago","cuanto tarda pago ficha","tiempo de confirmacion pago","cuando aparece mi pago","cuanto tarda sistema en reflejar pago","tiempo de espera pago uttt","cuando se valida mi pago","cuanto tarda pago en sistema","cuanto tarda deposito en reflejarse","tiempo reflejo pago uttt","cuando aparece pago en sistema","cuanto tarda validacion de pago","tiempo de procesamiento pago","cuanto tarda pago admision","cuando se actualiza mi pago"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 233
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Puedo realizar mi registro desde cualquier dispositivo o navegador?','Se recomienda realizar el registro desde una computadora y utilizar navegadores actualizados para evitar errores en la captura de datos. Aunque es posible hacerlo desde un dispositivo móvil, el uso de una computadora facilita el proceso y reduce posibles inconvenientes.','aspirantes',true,'["puedo usar celular para registro","puedo registrarme desde telefono","registro en celular uttt","puedo usar cualquier navegador","desde donde hago mi registro","puedo usar chrome o edge","registro desde computadora o celular","que navegador usar uttt","puedo registrarme desde movil","registro en telefono funciona","puedo usar cualquier dispositivo","desde donde llenar ficha","mejor dispositivo para registro","puedo usar safari para registro","registro desde laptop uttt","puedo hacer registro desde pc","recomendacion navegador uttt","registro desde celular es valido","puedo usar internet explorer","desde que dispositivo registrarme"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 234
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿El proceso de admisión es presencial o en línea?','El proceso de admisión combina ambas modalidades. El registro y algunos trámites se realizan en línea a través del portal de aspirantes, mientras que la evaluación diagnóstica se realiza de manera presencial en las instalaciones de la universidad.','aspirantes',true,'["proceso es en linea o presencial","admisión es en linea","examen es presencial uttt","como es proceso admision","registro es en linea uttt","proceso mixto admision","todo es en linea uttt","examen presencial o en linea","como funciona admision uttt","registro y examen como son","admisión presencial o virtual","proceso uttt como es","registro en linea examen presencial","admisión es presencial","proceso de ingreso como es","todo es presencial uttt","proceso es mixto uttt","como se hace admision","registro y examen modalidad","como es el proceso de ingreso"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');   

-- ID 235
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La UTTT cuenta con la carrera de Medicina?','Actualmente la Universidad Tecnológica de Tula-Tepeji no cuenta con la carrera de Medicina. Sin embargo, se ofrece la Licenciatura en Enfermería en el campus Tepetitlán, enfocada en la formación de profesionales del área de la salud. Si deseas consultar el plan de estudios o más información sobre esta carrera, puedes visitar el siguiente enlace: https://www.uttt.edu.mx/Enfermeria/','aspirantes',true,'["hay medicina en la uttt","tienen la carrera de medicina","quiero estudiar medicina uttt","licenciatura en medicina uttt","hay medico cirujano uttt","donde estudiar medicina uttt","uttt tiene medicina","hay carrera de medico uttt","medicina en uttt informacion","quiero ser doctor en uttt","ofrecen medicina uttt","hay medicina en tepetitlan","carrera de salud uttt","licenciatura de enfermeria uttt","que carreras de salud hay uttt","medicina convocatoria uttt","quiero estudiar enfermeria uttt","hay enfermeria en uttt","carrera de enfermeria tepetitlan","uttt carreras de salud"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  


-- ID 236
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si olvidé mi usuario o contraseña?','Si olvidaste tu usuario o contraseña, no te preocupes, puedes revisar tu correo electrónico donde se te proporcionaron tus datos de acceso al momento de registrarte. En caso de no encontrarlos o si no puedes acceder, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["olvide mi contraseña","olvide mi usuario","no recuerdo mi contraseña","no recuerdo mi usuario","como recuperar mi contraseña","como recuperar mi usuario","no puedo entrar porque olvide mi contraseña","olvide mis datos de acceso","recuperar acceso uttt","no tengo mi usuario","no tengo mi contraseña","como recuperar mi cuenta uttt","olvide mis datos de login","no recuerdo mis datos de registro","perdi mi contraseña uttt","no puedo acceder porque olvide datos","olvide mis credenciales","no se mi usuario ni contraseña","recuperar cuenta prefichas","no encuentro mis datos de acceso"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 237
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si no puedo ingresar al sistema?','Si no puedes ingresar al sistema, verifica que estés utilizando correctamente tu usuario y contraseña, así como una conexión estable a internet. También puedes intentar desde otro navegador o dispositivo. Si el problema persiste, no te preocupes, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["no puedo entrar al sistema","no puedo iniciar sesion","no me deja entrar","no puedo acceder a mi cuenta","error al iniciar sesion","no puedo ingresar uttt","problema para entrar al sistema","no puedo ver mi ficha","no puedo acceder al portal","error login uttt","no me deja iniciar sesion uttt","no puedo entrar prefichas","problema acceso sistema","no puedo entrar a mi registro","error al ingresar sistema","no puedo iniciar sesion uttt","no puedo acceder a prefichas","fallo al iniciar sesion","no me deja acceder sistema","error acceso plataforma"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');

-- ID 239
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué hago si la página no carga o presenta errores?','Si la página no carga o presenta errores, puede deberse a un problema de conexión a internet o a una falla temporal del sistema. Te recomendamos verificar tu conexión, actualizar la página o intentar desde otro navegador o dispositivo. Si el problema persiste, puedes acudir al Departamento de Sistemas, su correo es sistemas@uttt.edu.mx, o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["la pagina no carga","no abre la pagina uttt","error en la pagina","no funciona la pagina","pagina caida uttt","no puedo acceder a la pagina","error sistema uttt","no carga el portal","pagina no responde","error en prefichas","no funciona el sistema","problema con la pagina","no abre prefichas","pagina lenta uttt","error conexion uttt","no carga portal admision","fallo en la pagina uttt","problema con sistema uttt","pagina no disponible","error al abrir pagina"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');   


-- ID 240
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué es el TSU y cómo funciona?','El TSU (Técnico Superior Universitario) es un nivel de educación superior que se cursa en aproximadamente 2 años y está enfocado en la formación práctica y profesional. Al concluir este nivel, puedes incorporarte al campo laboral o continuar tus estudios para obtener una Ingeniería o Licenciatura en la misma área, lo que se conoce como continuidad de estudios.','aspirantes',true,'["que es tsu","que significa tsu","que es tecnico superior universitario","que es tsu uttt","que es el nivel tsu","como funciona el tsu","cuanto dura el tsu","tsu que es","que es tsu en universidad","tsu que significa","nivel tsu que es","que es carrera tsu","tsu cuanto dura","que es tsu en mexico","que significa tecnico superior universitario","como funciona tsu uttt","que es tsu y licenciatura","tsu e ingenieria diferencia","que es tsu y para que sirve","que es nivel tsu uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  


-- ID 241
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Hay clases los sábados en la UTTT?','Los horarios de clases en la UTTT dependen del programa educativo y del turno asignado. Algunas actividades académicas o clases pueden programarse en sábado, aunque esto no aplica para todos los casos. Te recomendamos consultar tu horario oficial una vez inscrito o comunicarte con tu coordinación académica para obtener información específica.','aspirantes',true,'["hay clases los sabados","clases sabado uttt","hay clases en sabado","se estudia en sabado uttt","hay clases fines de semana","clases sabados universidad","puedo tener clases en sabado","hay clases sabado en uttt","clases en fin de semana uttt","horarios sabado uttt","hay clases los fines de semana","puedo estudiar sabado uttt","clases sabatino uttt","hay turno sabatino","clases sabado obligatorio","hay clases extra sabado","pueden poner clases en sabado","horarios incluyen sabado","clases sabado universidad uttt","hay clases en sabado si o no"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  

-- ID 242
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuántas etapas de admisión hay y cuáles son las fechas?','Actualmente el proceso de admisión se realiza conforme a la convocatoria vigente. Para este año, el proceso comprende los meses de mayo y junio. Te recomendamos consultar la convocatoria para conocer las fechas específicas de cada etapa. Para mayor información, puedes comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["cuantas etapas admision","etapas de admision uttt","como es el proceso de admision","fases del proceso uttt","cuantas fases tiene admision","etapas registro examen resultados","como se divide admision uttt","pasos de admision uttt","cuantas etapas tiene el proceso","fases del proceso de ingreso","etapas de ingreso uttt","como es el proceso completo","cuantas fases admision uttt","proceso de admision etapas","pasos para ingresar uttt","como es el proceso de ingreso","etapas ficha examen resultados","proceso admision como funciona","cuantas etapas tiene ingreso","fases admision universidad"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');


-- ID 243
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('Si ya presenté el examen de admisión en años anteriores, ¿tengo que volver a hacerlo?','Como asistente virtual no puedo confirmar casos específicos relacionados con procesos anteriores. Te recomendamos comunicarte con el Departamento de Comunicación e Imagen, donde podrán brindarte información detallada sobre tu situación. Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["ya hice examen antes tengo que hacerlo otra vez","examen anterior sirve uttt","puedo usar examen de años pasados","ya presente examen tengo que repetirlo","examen pasado es valido","tengo examen anterior uttt sirve","ya hice examen admision antes","puedo reutilizar mi examen","examen anterior se toma en cuenta","ya habia presentado examen uttt","sirve examen de otro año","examen pasado valido uttt","tengo resultado anterior sirve","puedo usar examen viejo uttt","examen anterior aplica","ya hice examen antes debo repetir","examen previo cuenta uttt","puedo validar examen anterior","ya presente examen debo hacerlo otra vez","examen pasado se puede usar"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  


-- ID 244
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuándo inician los cursos propedéuticos o de inducción?','El curso propedéutico inicia una vez concluida la convocatoria de admisión. Para conocer fechas y detalles específicos, es importante mantenerse al pendiente de la información oficial. Como asistente virtual, esta información puede actualizarse posteriormente en el sistema; por el momento, te recomendamos comunicarte con el Departamento de Comunicación e Imagen para recibir información más detallada. Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["cuando inicia curso propedeutico","curso de induccion cuando empieza","cuando son los cursos de induccion","cuando inicia propedeutico uttt","curso propedeutico fecha","induccion cuando inicia uttt","cuando empiezan cursos de ingreso","curso de induccion fechas","cuando inicia el curso de induccion","propedeutico cuando empieza","curso de ingreso cuando es","cuando inicia induccion universidad","curso propedeutico informacion","cuando son cursos propedeuticos","induccion fechas uttt","cuando inicia curso de ingreso","curso propedeutico uttt cuando","induccion universidad cuando empieza","cuando empieza el propedeutico","curso de induccion uttt fechas"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  


-- ID 245
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La UTTT ofrece la carrera de cocina?','La Universidad Tecnológica de Tula-Tepeji no ofrece la carrera de cocina como tal, pero sí cuenta con la Licenciatura en Gastronomía, la cual se puede cursar en modalidad escolarizada (modelo tradicional) y en modalidad mixta. Este programa se ofrece en el campus Tula-Tepeji. Para consultar el plan de estudios y más información, puedes visitar: https://www.uttt.edu.mx/ProgramasEducativos.html','aspirantes',true,'["hay carrera de cocina","tienen cocina uttt","carrera de chef uttt","estudiar cocina uttt","gastronomia uttt informacion","hay gastronomia en uttt","quiero estudiar gastronomia","licenciatura en gastronomia uttt","carrera de chef universidad uttt","gastronomia modalidad uttt","donde estudiar gastronomia uttt","uttt tiene gastronomia","carrera de cocina universidad","quiero ser chef uttt","gastronomia campus tula","hay gastronomia en tula tepeji","gastronomia modalidad mixta uttt","carrera de cocina existe uttt","programa gastronomia uttt","licenciatura gastronomia informacion"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  



-- ID 246
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Hay cursos de inglés y dónde puedo solicitar informes?','La UTTT ofrece cursos de inglés a través del área correspondiente. Las convocatorias y fechas se publican en el sitio oficial de Facebook: https://www.facebook.com/UTTTMx. Para mayor información, puedes comunicarte al correo educacion.continua@uttt.edu.mx o al teléfono 773 732 9100 ext. 257 y 203.','aspirantes',true,'["cursos de ingles uttt","ingles uttt informes","hay cursos de ingles","donde tomar ingles uttt","informacion cursos ingles","ingles en la universidad uttt","curso de ingles costos uttt","clases de ingles uttt","donde estudiar ingles uttt","ingles educacion continua uttt","cursos de ingles fechas uttt","ingles convocatoria uttt","cursos ingles facebook uttt","informes ingles uttt","clases ingles universidad","curso ingles contacto uttt","ingles educacion continua informes","curso ingles telefono uttt","ingles donde preguntar uttt","cursos idiomas uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  


-- ID 247
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Qué ingenierías y licenciaturas ofrece la UTTT?','La Universidad Tecnológica de Tula-Tepeji ofrece ingenierías y licenciaturas en distintos campus. Para brindarte información más específica, indícanos el campus de tu interés y escribe alguna de las siguientes opciones: "Ingenierías campus Tula-Tepeji", "Licenciaturas campus Tula-Tepeji", "Ingenierías campus Chapulhuacán" o "Licenciaturas campus Tepetitlán". Con gusto te mostraremos la oferta educativa correspondiente.','aspirantes',true,'["ingenierias y licenciaturas uttt","que ingenierias hay uttt","que licenciaturas hay uttt","oferta educativa ingenierias licenciaturas","carreras ingenierias licenciaturas uttt","que puedo estudiar uttt","ingenierias disponibles uttt","licenciaturas disponibles uttt","carreras que ofrece uttt","oferta educativa completa uttt","programas educativos ingenierias licenciaturas","que carreras hay ingenierias licenciaturas","oferta academica uttt completa","que ingenierias y licenciaturas hay","programas disponibles uttt","que estudiar en uttt","carreras universidad uttt","ingenierias licenciaturas campus uttt","oferta por campus uttt","programas educativos uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');   


-- ID 248
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Solo hay un turno en la UTTT?','Los turnos en la UTTT dependen de las características académicas y organizativas de cada programa educativo. Para conocer información específica sobre los turnos disponibles, te recomendamos comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["solo hay un turno","hay turno vespertino uttt","hay turno matutino uttt","cuantos turnos hay uttt","turnos universidad uttt","hay clases en la tarde uttt","hay clases en la mañana uttt","turnos disponibles uttt","puedo elegir turno uttt","hay turno nocturno uttt","como son los turnos uttt","hay varios turnos uttt","turno sabatino uttt","horarios por turno uttt","hay turno unico uttt","puedo escoger turno uttt","turnos carrera uttt","hay turno flexible uttt","como funcionan los turnos uttt","turnos en la universidad uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  


-- ID 249
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿La Licenciatura en Administración cuenta con modalidad mixta o virtual?','En la Universidad Tecnológica de Tula-Tepeji no todos los programas se ofrecen únicamente en modalidad escolarizada (presencial), ya que también existe la modalidad mixta virtual. Dentro de esta modalidad se ofertan programas como Ingeniería en Mecatrónica, Ingeniería en Mantenimiento Industrial, Licenciatura en Contaduría y Licenciatura en Gastronomía. Para conocer la disponibilidad específica de la Licenciatura en Administración y otras carreras, te recomendamos consultar la oferta educativa actual o comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["administracion modalidad mixta","administracion virtual uttt","licenciatura administracion en linea","administracion modalidad virtual uttt","administracion es presencial o virtual","hay administracion mixta uttt","puedo estudiar administracion en linea","administracion modalidad mixta uttt","administracion en linea universidad uttt","administracion virtual disponible","administracion presencial o mixta","licenciatura administracion modalidad","administracion se puede estudiar en linea","hay modalidad virtual administracion","administracion en linea uttt","modalidad mixta administracion","administracion en linea universidad","administracion virtual carrera","administracion modalidad escolarizada o virtual","administracion en modalidad mixta"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  


-- ID 250
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cuándo se abre la convocatoria para la carrera de Medicina?','Actualmente la Universidad Tecnológica de Tula-Tepeji no cuenta con la carrera de Medicina. Te recomendamos mantenerte al pendiente de los medios oficiales para cualquier actualización futura. Para más información, puedes comunicarte con el Departamento de Comunicación e Imagen: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596 | Horario de atención: Lunes a Viernes de 9:00 a 17:00 horas.','aspirantes',true,'["convocatoria medicina uttt","cuando abren medicina uttt","medicina convocatoria fecha","hay convocatoria medicina uttt","cuando sale medicina uttt","convocatoria medico uttt","cuando abre medicina universidad","medicina fecha registro uttt","convocatoria carrera medicina","cuando sale convocatoria medicina","medicina inscripciones uttt","convocatoria medicina universidad","registro medicina uttt cuando","cuando puedo estudiar medicina uttt","medicina apertura convocatoria","convocatoria medico cirujano uttt","cuando abren inscripciones medicina","medicina universidad convocatoria","registro medicina fecha","medicina uttt convocatoria"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');  


-- ID 251
INSERT INTO faqs (question, answer, category, is_active, variantes, nombre, puesto, unidadorganica) VALUES ('¿Cómo puedo contactar a la universidad o recibir atención personalizada?','Si necesitas apoyo o atención personalizada, puedes comunicarte con el Departamento de Comunicación e Imagen a través de los siguientes medios: Teléfono: 773 732 9100 ext. 241 y 256 | Correo electrónico: comunicacion@uttt.edu.mx | WhatsApp (solo mensajes): 773 680 1596. También puedes consultar el directorio institucional en: https://www.uttt.edu.mx/Directorio.html. Si prefieres atención presencial, puedes acudir directamente al campus en un horario de lunes a viernes de 9:00 a 17:00 horas.','aspirantes',true,'["contacto uttt","telefono uttt","como contactar uttt","directorio uttt","numero de la universidad","donde llamar uttt","correo uttt","whatsapp uttt","atencion universidad uttt","informes uttt contacto","como comunicarme con la universidad","datos de contacto uttt","telefono comunicacion uttt","contacto comunicacion e imagen","donde pedir informes uttt","numero informes uttt","como hablar a uttt","contacto oficial uttt","informes universidad telefono","como contactar universidad uttt"]'::jsonb,'Brenda Magaly Arguelles Trillo','Jefe (a) de departamento','Departamento de Ingreso y Captación');   